#!/usr/bin/env node
/**
 * 生成 kugou_api_server/bundled_entry.js
 *
 * 为什么需要它：
 *   安卓运行时只把 server_bundle.js 拷贝到 files/nodejs-project/，没有 module/ 目录。
 *   因此 server.js 在运行时扫描 module/ 目录会得到空列表，所有接口都返回 Express 默认 404。
 *   必须把全部 module/*.js 静态内联进单个 bundle。
 *
 *   但 server_android.js / server_entry.js / modules_index.js 用的都是
 *   require('./module/' + name + '.js') 这种「动态 require」——esbuild 无法静态分析，
 *   于是打出来的包里根本不含模块实现。
 *
 *   本脚本生成 bundled_entry.js，里面是「静态字面量 require」：
 *     'register_dev': require('./module/register_dev.js'),
 *   esbuild 必然内联这些模块，从而得到一个自包含的 server_bundle.js。
 */
const fs = require('fs');
const path = require('path');

const moduleDir = path.resolve(__dirname, '..', 'kugou_api_server', 'module');
const outFile = path.resolve(__dirname, '..', 'kugou_api_server', 'bundled_entry.js');

if (!fs.existsSync(moduleDir)) {
  console.error('[gen] module dir not found:', moduleDir);
  process.exit(1);
}

const files = fs.readdirSync(moduleDir)
  .filter((f) => f.endsWith('.js') && !f.startsWith('_'))
  .map((f) => f.slice(0, -3))
  .sort();

const requireLines = files
  .map((name) => `  '${name}': require('./module/${name}.js'),`)
  .join('\n');

const content = `// AUTO-GENERATED by scripts/gen_node_bundle_entry.js — DO NOT EDIT MANUALLY.
// 静态字面量 require，确保 esbuild 能把所有 module/*.js 内联进单个 bundle。
const modules = {
${requireLines}
};

// 构建路由定义：register_dev -> /register/dev, search_suggest -> /search/suggest ...
const moduleDefs = Object.entries(modules)
  .filter(([, mod]) => typeof mod === 'function')
  .map(([name, mod]) => ({
    identifier: name,
    route: '/' + name.replace(/_/g, '/'),
    module: mod,
  }))
  // 倒序：保证更具体的路由（如 /search/suggest）先于通用路由 /search 注册，
  // 避免 Express 的 app.use 前缀匹配把子路由拦截掉。
  .reverse();

// 交给 server.js 的 consturctServer 使用（server.js:
//   const moduleDefinitions = moduleDefs || global.__BUNDLED_MODULE_DEFS__ || (await getModulesDefinitions(...))
// ）
global.__BUNDLED_MODULE_DEFS__ = moduleDefs;

require('./server').startService();
`;

fs.writeFileSync(outFile, content);
console.log('[gen] wrote', outFile, '(' + files.length + ' modules)');
